'use client';
import { useEffect, useState } from 'react';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Input } from '@/components/ui/input';
import { motion } from 'framer-motion';
import { useAuth } from '@/context/AuthContext';


const profileSchema = z.object({
  name: z.string().min(2, 'Name must be at least 2 characters'),
  email: z.string().email('Invalid email address'),
});

export default function EditProfilePage() {
  const { token, detailsProfile } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);

  const form = useForm<z.infer<typeof profileSchema>>({
    resolver: zodResolver(profileSchema),
    defaultValues: {
      name: '',
      email: '',
    },
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await fetch(`http://localhost:8080/profile`, {
        method: 'PUT',
        headers: {
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(detailsProfile),
      });

      const data = await res.json();

      toast({
        title: 'Success',
        description: 'Profile updated successfully.',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Something went wrong.',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className='min-h-screen bg-gradient-to-br from-white to-purple-100 p-6 flex items-center justify-center'>
      <motion.form
        onSubmit={handleSubmit}
        className='w-full max-w-lg bg-white rounded-xl shadow-md p-6 space-y-4 border border-gray-200'
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h2 className='text-2xl font-bold text-center text-purple-700'>
          Edit Profile
        </h2>
        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className='space-y-6'
          >
            {/* Email Field */}
            <FormField
              control={form.control}
              name='email'
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Email</FormLabel>
                  <FormControl>
                    <motion.div
                      whileHover={{ scale: 1.02 }}
                      className='relative'
                    >
                      <Mail className='absolute right-3 top-1/2 transform -translate-y-1/2 text-purple-400' />
                      <Input
                        placeholder='your@email.com'
                        className='w-full rounded-lg p-3 pr-10 border-2 border-purple-100 focus:border-purple-500 transition-all'
                        {...field}
                      />
                    </motion.div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Password Field */}
            <FormField
              control={form.control}
              name='password'
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Password</FormLabel>
                  <FormControl>
                    <motion.div
                      whileHover={{ scale: 1.02 }}
                      className='relative'
                    >
                      <Lock className='absolute right-3 top-1/2 transform -translate-y-1/2 text-purple-400' />
                      <Input
                        type='password'
                        placeholder='••••••••'
                        className='w-full rounded-lg p-3 pr-10 border-2 border-purple-100 focus:border-purple-500 transition-all'
                        {...field}
                      />
                    </motion.div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <motion.button
              type='submit'
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.98 }}
              className={`w-full bg-gradient-to-r from-purple-600 to-indigo-600 text-white font-bold py-3 rounded-lg transition-all ${
                form.formState.isSubmitting ? 'opacity-80' : 'hover:shadow-lg'
              }`}
              disabled={form.formState.isSubmitting}
            >
              {form.formState.isSubmitting ? (
                <div className='flex items-center justify-center'>
                  <Loader2 className='animate-spin mr-2' />
                  Save Changes ...
                </div>
              ) : (
                'Sign In'
              )}
            </motion.button>
          </form>
        </Form>
        {/* <Button
          type='submit'
          className='w-full'
        >
          Save Changes
        </Button> */}
      </motion.form>
    </div>
  );
}
